<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Explorer</title>
<style>
  body { font-family: sans-serif; margin: 0; padding: 10px; background: #f0f0f0; }
  #ui { display: flex; gap: 20px; margin-bottom: 10px; align-items: center; }
  #ui > div { font-size: 1.2em; }
  #reset { padding: 8px 16px; font-size: 1em; cursor: pointer; }
  #maze { border: 2px solid #333; background: #fff; width: 600px; height: 600px; }
  canvas { display: block; }
</style>
</head>
<body>
<div id="ui">
  <div>Completed: <span id="completed">0</span>/24</div>
  <div>Timer: <span id="timer">0</span></div>
  <button id="reset">Reset</button>
</div>
<div id="maze"><canvas id="mazeCanvas"></canvas></div>

<script>
// ---------- Seeded RNG (mulberry32) ----------
function createRNG(seed) {
  let state = seed >>> 0;
  return function() {
    state += 0x6D2B79F5;
    let t = Math.imul(state ^ (state >>> 15), 1 | state);
    t ^= t + Math.imul(t ^ (t >>> 7), 61 | t);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ---------- Maze Generation ----------
const DIRS = ['n','e','s','w'];
const DR = [-1,0,1,0];
const DC = [0,1,0,-1];
const OPPOSITE = {n:'s', e:'w', s:'n', w:'e'};

function generateMaze(rows, cols, rng) {
  const grid = Array.from({length: rows}, () =>
    Array.from({length: cols}, () => ({
      walls: {n:true, e:true, s:true, w:true},
      visited: false
    })));
  const stack = [{r:0, c:0}];
  grid[0][0].visited = true;
  while (stack.length) {
    const cur = stack[stack.length-1];
    const neighbors = [];
    for (let i=0;i<4;i++) {
      const nr = cur.r + DR[i], nc = cur.c + DC[i];
      if (nr>=0 && nr<rows && nc>=0 && nc<cols && !grid[nr][nc].visited) {
        neighbors.push({r:nr, c:nc, dir:i});
      }
    }
    if (neighbors.length) {
      const idx = Math.floor(rng() * neighbors.length);
      const next = neighbors[idx];
      const dName = DIRS[next.dir], opp = DIRS[(next.dir+2)%4];
      grid[cur.r][cur.c].walls[dName] = false;
      grid[next.r][next.c].walls[opp] = false;
      grid[next.r][next.c].visited = true;
      stack.push(next);
    } else {
      stack.pop();
    }
  }
  return {rows, cols, grid,
    walls(r,c) { return grid[r][c].walls; }
  };
}

// ---------- Bot Class ----------
class Bot {
  constructor(id, spawn, exit, maze, rng) {
    this.id = id;
    this.maze = maze;
    this.exit = exit;
    this.currentCell = {r:spawn.r, c:spawn.c};
    this.animStartCell = null;
    this.animEndCell = null;
    this.animStartTime = 0;
    this.path = [{r:spawn.r, c:spawn.c}];
    this.deadEnds = [];
    this.deadEndsSet = new Set();
    this.finishTick = null;
    this.finished = false;
    this.stack = [{r:spawn.r, c:spawn.c}];
    this.visitedEdges = Array.from({length: maze.rows}, () =>
      Array.from({length: maze.cols}, () => [0,0,0,0]));
    this.dirOrder = [0,1,2,3];
    for (let i=this.dirOrder.length-1;i>0;i--) {
      const j = Math.floor(rng() * (i+1));
      [this.dirOrder[i], this.dirOrder[j]] = [this.dirOrder[j], this.dirOrder[i]];
    }
    this.color = `hsl(${id * 15}, 80%, 50%)`;
  }

  getDirection(from, to) {
    if (to.r === from.r-1) return 0;
    if (to.c === from.c+1) return 1;
    if (to.r === from.r+1) return 2;
    if (to.c === from.c-1) return 3;
    return -1;
  }

  step(elapsed) {
    if (this.finished) return;
    const cur = this.currentCell;
    for (const dir of this.dirOrder) {
      const wallKey = DIRS[dir];
      if (!this.maze.walls(cur.r, cur.c)[wallKey]) {
        if (this.visitedEdges[cur.r][cur.c][dir] < 2) {
          const nr = cur.r + DR[dir], nc = cur.c + DC[dir];
          this.moveTo({r:nr, c:nc}, dir, true, elapsed);
          return;
        }
      }
    }
    if (this.stack.length > 1) {
      const key = `${cur.r},${cur.c}`;
      if (!this.deadEndsSet.has(key)) {
        this.deadEnds.push({r:cur.r, c:cur.c});
        this.deadEndsSet.add(key);
      }
      this.stack.pop();
      const prev = this.stack[this.stack.length-1];
      const dir = this.getDirection(cur, prev);
      this.moveTo(prev, dir, false, elapsed);
    }
  }

  moveTo(newCell, dir, isForward, elapsed) {
    this.visitedEdges[this.currentCell.r][this.currentCell.c][dir]++;
    const opp = (dir+2)%4;
    this.visitedEdges[newCell.r][newCell.c][opp]++;
    if (isForward) this.stack.push(newCell);
    this.currentCell = newCell;
    this.path.push({r:newCell.r, c:newCell.c});
    if (newCell.r === this.exit.r && newCell.c === this.exit.c) {
      this.finished = true;
      this.finishTick = elapsed + 1;
    }
  }
}

// ---------- Game State ----------
const ROWS = 20, COLS = 20;
const CANVAS_SIZE = 600;
const CELL_SIZE = CANVAS_SIZE / COLS;
const TICK_INTERVAL = 100; // ms

let maze = null;
let bots = [];
let elapsed = 0;
let allFinished = false;
let intervalId = null;
let renderLoopRunning = false;
const spawn = {r:0, c:0};
const exit = {r:ROWS-1, c:COLS-1};
const canvas = document.getElementById('mazeCanvas');
const ctx = canvas.getContext('2d');
canvas.width = CANVAS_SIZE;
canvas.height = CANVAS_SIZE;

// ---------- Helpers ----------
function cellToPixel(cell) {
  return {x: (cell.c + 0.5) * CELL_SIZE, y: (cell.r + 0.5) * CELL_SIZE};
}

function updateTimer() {
  document.getElementById('timer').textContent = elapsed;
}
function updateCompleted() {
  document.getElementById('completed').textContent = bots.filter(b=>b.finished).length;
}

// ---------- Simulation Step ----------
function advanceTick() {
  if (allFinished) return;
  const now = performance.now();
  for (const bot of bots) {
    if (!bot.finished) {
      bot.animStartCell = {r:bot.currentCell.r, c:bot.currentCell.c};
      bot.step(elapsed);
      bot.animEndCell = {r:bot.currentCell.r, c:bot.currentCell.c};
      bot.animStartTime = now;
    }
  }
  elapsed++;
  updateTimer();
  updateCompleted();
  if (bots.every(b=>b.finished)) {
    allFinished = true;
    if (intervalId) { clearInterval(intervalId); intervalId = null; }
  }
}

// ---------- Rendering ----------
function drawMaze() {
  ctx.strokeStyle = '#000';
  ctx.lineWidth = 2;
  for (let r=0;r<ROWS;r++) {
    for (let c=0;c<COLS;c++) {
      const x = c * CELL_SIZE, y = r * CELL_SIZE;
      const w = maze.walls(r,c);
      if (w.n) { ctx.beginPath(); ctx.moveTo(x,y); ctx.lineTo(x+CELL_SIZE,y); ctx.stroke(); }
      if (w.e) { ctx.beginPath(); ctx.moveTo(x+CELL_SIZE,y); ctx.lineTo(x+CELL_SIZE,y+CELL_SIZE); ctx.stroke(); }
      if (w.s) { ctx.beginPath(); ctx.moveTo(x,y+CELL_SIZE); ctx.lineTo(x+CELL_SIZE,y+CELL_SIZE); ctx.stroke(); }
      if (w.w) { ctx.beginPath(); ctx.moveTo(x,y); ctx.lineTo(x,y+CELL_SIZE); ctx.stroke(); }
    }
  }
}

function drawBots() {
  const now = performance.now();
  for (const bot of bots) {
    let drawX, drawY;
    if (bot.animStartCell && bot.animEndCell) {
      const prog = Math.min(1, (now - bot.animStartTime) / TICK_INTERVAL);
      if (prog < 1) {
        const s = cellToPixel(bot.animStartCell);
        const e = cellToPixel(bot.animEndCell);
        drawX = s.x + (e.x - s.x) * prog;
        drawY = s.y + (e.y - s.y) * prog;
      } else {
        bot.animStartCell = null; bot.animEndCell = null;
        const p = cellToPixel(bot.currentCell);
        drawX = p.x; drawY = p.y;
      }
    } else {
      const p = cellToPixel(bot.currentCell);
      drawX = p.x; drawY = p.y;
    }
    ctx.beginPath();
    ctx.arc(drawX, drawY, CELL_SIZE * 0.3, 0, Math.PI*2);
    ctx.fillStyle = bot.color;
    ctx.fill();
    ctx.strokeStyle = '#000'; ctx.lineWidth = 1; ctx.stroke();
  }
}

function render() {
  ctx.clearRect(0,0,CANVAS_SIZE,CANVAS_SIZE);
  drawMaze();
  drawBots();
  requestAnimationFrame(render);
}

// ---------- Public API ----------
window.game = {
  tick(n) {
    if (allFinished) return;
    for (let i=0;i<n;i++) {
      advanceTick();
      if (allFinished) break;
    }
  },
  reset(seed) {
    if (intervalId) { clearInterval(intervalId); intervalId = null; }
    const rng = seed !== undefined ? createRNG(seed) : createRNG(Date.now());
    maze = generateMaze(ROWS, COLS, rng);
    bots = [];
    for (let i=0;i<24;i++) {
      const botRng = createRNG(Math.floor(rng() * 0x100000000));
      bots.push(new Bot(i, spawn, exit, maze, botRng));
    }
    elapsed = 0;
    allFinished = false;
    updateTimer();
    updateCompleted();
    intervalId = setInterval(advanceTick, TICK_INTERVAL);
  },
  get elapsed() { return elapsed; },
  get size() { return {rows:ROWS, cols:COLS}; },
  get spawn() { return spawn; },
  get exit() { return exit; },
  walls(r,c) { return maze ? maze.walls(r,c) : {n:true,e:true,s:true,w:true}; },
  get bots() { return bots; }
};

// ---------- UI Events ----------
document.getElementById('reset').addEventListener('click', () => window.game.reset());

// ---------- Start ----------
window.game.reset();
if (!renderLoopRunning) { renderLoopRunning = true; requestAnimationFrame(render); }
</script>
</body>
</html>
